Consumer overrides only what they need:

// Stay open after selecting an item
<MultiSelect
items={options}
stateReducer={(newState, action) => {
if (action.type === 'toggle_item') {
return { ...newState, isOpen: true } // override: keep open
}
return newState
}}
/>

